"use client"

import { useState, useEffect } from "react"
import { motion, AnimatePresence } from "framer-motion"
import { Button } from "@/components/ui/button"
import { Menu, X, ChevronDown } from "lucide-react"
import FN3Logo from "@/components/logos/fn3-logo"

const navigation = [
  { name: 'Platform', href: '#platform' },
  { name: 'Portfolio', href: '#portfolio' },
  { name: 'Architecture', href: '#architecture' },
  {
    name: 'Ventures',
    href: '#ventures',
    hasDropdown: true,
    dropdownItems: [
      { name: 'SUBZII', href: '#subzii', description: 'Event ticketing platform' },
      { name: 'DETAILMAPS', href: '#detailmaps', description: 'Auto-care optimization' },
      { name: 'DRYJETS', href: '#dryjets', description: 'On-demand services' },
      { name: 'DAWA', href: '#dawa', description: 'Healthcare infrastructure' },
    ]
  },
  { name: 'Contact', href: '#contact' },
]

export function NavigationPro() {
  const [isOpen, setIsOpen] = useState(false)
  const [scrolled, setScrolled] = useState(false)

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50)
    }
    window.addEventListener('scroll', handleScroll)
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  return (
    <motion.header
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
      className={`fixed top-0 w-full z-50 transition-all duration-500 ${
        scrolled
          ? 'bg-white/90 backdrop-blur-xl border-b border-gray-200 shadow-lg'
          : 'bg-transparent'
      }`}
    >
      <nav className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
        <div className="flex items-center justify-between">

          {/* Logo */}
          <motion.div
            whileHover={{ scale: 1.05 }}
            className="cursor-pointer"
          >
            <FN3Logo
              variant="full"
              theme={scrolled ? "light" : "dark"}
              className={scrolled ? "" : "drop-shadow-lg"}
            />
          </motion.div>

          {/* Desktop Navigation */}
          <div className="hidden lg:flex items-center space-x-8">
            {navigation.map((item) => (
              <div key={item.name} className="relative group">
                <a
                  href={item.href}
                  className={`flex items-center gap-1 px-3 py-2 rounded-lg transition-all duration-200 font-medium ${
                    scrolled
                      ? 'text-gray-700 hover:text-blue-600 hover:bg-blue-50'
                      : 'text-white hover:text-blue-200 hover:bg-white/10'
                  }`}
                >
                  {item.name}
                  {item.hasDropdown && <ChevronDown className="w-4 h-4 ml-1" />}
                </a>

                {/* Dropdown Menu */}
                {item.hasDropdown && item.dropdownItems && (
                  <div className="absolute top-full left-0 mt-2 w-64 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-50">
                    <div className="bg-white rounded-xl shadow-2xl border border-gray-200 p-2">
                      {item.dropdownItems.map((dropdownItem) => (
                        <a
                          key={dropdownItem.name}
                          href={dropdownItem.href}
                          className="block px-4 py-3 rounded-lg hover:bg-gray-50 transition-colors"
                        >
                          <div className="font-semibold text-gray-900">
                            {dropdownItem.name}
                          </div>
                          <div className="text-sm text-gray-500 mt-1">
                            {dropdownItem.description}
                          </div>
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* CTA Button - Desktop */}
          <div className="hidden lg:block">
            <Button
              size="lg"
              className={`font-semibold shadow-lg transition-all duration-200 ${
                scrolled
                  ? 'bg-blue-600 text-white hover:bg-blue-700'
                  : 'bg-white text-black hover:bg-white/90'
              }`}
            >
              Partner With Us
            </Button>
          </div>

          {/* Mobile Menu Button */}
          <Button
            variant="ghost"
            size="icon"
            className={`lg:hidden ${scrolled ? 'text-gray-700' : 'text-white'}`}
            onClick={() => setIsOpen(!isOpen)}
          >
            {isOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </Button>
        </div>

        {/* Mobile Navigation */}
        <AnimatePresence>
          {isOpen && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              transition={{ duration: 0.3 }}
              className="lg:hidden overflow-hidden mt-4"
            >
              <div className="bg-white/95 backdrop-blur-xl rounded-2xl border border-gray-200 p-4 shadow-2xl">
                <div className="space-y-2">
                  {navigation.map((item) => (
                    <div key={item.name}>
                      <a
                        href={item.href}
                        className="block px-4 py-3 text-gray-700 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors font-medium"
                        onClick={() => setIsOpen(false)}
                      >
                        {item.name}
                      </a>

                      {/* Mobile dropdown items */}
                      {item.hasDropdown && item.dropdownItems && (
                        <div className="ml-4 mt-2 space-y-1">
                          {item.dropdownItems.map((dropdownItem) => (
                            <a
                              key={dropdownItem.name}
                              href={dropdownItem.href}
                              className="block px-3 py-2 text-sm text-gray-600 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                              onClick={() => setIsOpen(false)}
                            >
                              {dropdownItem.name}
                            </a>
                          ))}
                        </div>
                      )}
                    </div>
                  ))}

                  <div className="pt-4 border-t border-gray-200 mt-4">
                    <Button
                      size="lg"
                      className="w-full bg-blue-600 text-white hover:bg-blue-700 font-semibold"
                    >
                      Partner With Us
                    </Button>
                  </div>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </nav>
    </motion.header>
  )
}